                // Draw point as a small circle
                ctx.beginPath();
                ctx.arc(point.x, point.y, 1.5, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        function animate() {
            renderDonut();
            requestAnimationFrame(animate);
        }

        animate();
    </script>
</body>
</html>
